// File generated by flutterfire configure
// IMPORTANT: API keys are loaded from .env file for security
import 'package:firebase_core/firebase_core.dart';
import 'package:flutter_dotenv/flutter_dotenv.dart';

class DefaultFirebaseOptions {
  static FirebaseOptions get currentPlatform {
    return DefaultFirebaseOptions.ios;
  }

  static FirebaseOptions get ios {
    return FirebaseOptions(
      apiKey: _getApiKey('ios'),
      appId: _getAppId('ios'),
      messagingSenderId: _getMessagingSenderId(),
      projectId: _getProjectId(),
      storageBucket: _getStorageBucket(),
      iosBundleId: 'com.ymusic.dev',
    );
  }

  static FirebaseOptions get android {
    return FirebaseOptions(
      apiKey: _getApiKey('android'),
      appId: _getAppId('android'),
      messagingSenderId: _getMessagingSenderId(),
      projectId: _getProjectId(),
      storageBucket: _getStorageBucket(),
    );
  }

  static FirebaseOptions get web {
    return FirebaseOptions(
      apiKey: _getApiKey('web'),
      appId: _getAppId('web'),
      messagingSenderId: _getMessagingSenderId(),
      projectId: _getProjectId(),
      authDomain: '${_getProjectId()}.firebaseapp.com',
      storageBucket: _getStorageBucket(),
    );
  }

  // Load credentials from environment variables
  static String _getApiKey(String platform) {
    final key = dotenv.env['FIREBASE_API_KEY_${platform.toUpperCase()}'];
    if (key == null || key.isEmpty) {
      throw Exception(
        'Firebase API key for $platform not configured. '
        'Set FIREBASE_API_KEY_$platform in .env file'
      );
    }
    return key;
  }

  static String _getAppId(String platform) {
    final id = dotenv.env['FIREBASE_APP_ID_${platform.toUpperCase()}'];
    if (id == null || id.isEmpty) {
      throw Exception(
        'Firebase App ID for $platform not configured. '
        'Set FIREBASE_APP_ID_$platform in .env file'
      );
    }
    return id;
  }

  static String _getMessagingSenderId() {
    final id = dotenv.env['FIREBASE_MESSAGING_SENDER_ID'];
    if (id == null || id.isEmpty) {
      throw Exception(
        'Firebase Messaging Sender ID not configured. '
        'Set FIREBASE_MESSAGING_SENDER_ID in .env file'
      );
    }
    return id;
  }

  static String _getProjectId() {
    return dotenv.env['FIREBASE_PROJECT_ID'] ?? 'ymusic-dev';
  }

  static String _getStorageBucket() {
    return dotenv.env['FIREBASE_STORAGE_BUCKET'] ??
        '${_getProjectId()}.firebasestorage.app';
  }
}
